interface HttpRequest {
  method: 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';
  url: string;
  status_code: number;
  content_type?: string;
  body_size?: number;
}

interface DatabaseRecord {
  table_name: string;
  primary_key: number;
  created_at: string;
  updated_at?: string;
  deleted: boolean;
  version: number;
}

interface LogEntry {
  level: 'debug' | 'info' | 'warn' | 'error' | 'fatal';
  message: string;
  timestamp: number;
  source: string;
  stack_trace?: string;
  correlation_id?: string;
}

interface CacheEntry {
  key: string;
  value: string;
  ttl_seconds: number;
  hit_count: number;
  last_accessed: number;
  evictable: boolean;
}

interface DeploymentStatus {
  environment: 'development' | 'staging' | 'production';
  version: string;
  healthy: boolean;
  replica_count: number;
  last_deploy: string;
}

interface QueueMessage {
  queue_name: string;
  message_id: string;
  priority: 'low' | 'normal' | 'high' | 'critical';
  payload: string;
  retry_count: number;
  dead_letter: boolean;
}

interface FileMetadata {
  path: string;
  size_bytes: number;
  mime_type: string;
  checksum: string;
  readable: boolean;
  writable: boolean;
  last_modified: number;
}

interface AuthToken {
  token_type: 'bearer' | 'basic' | 'api_key';
  access_token: string;
  expires_in: number;
  scope?: string;
  refresh_token?: string;
}

interface MetricPoint {
  name: string;
  value: number;
  unit: 'ms' | 'bytes' | 'count' | 'percent';
  tags: string[];
  timestamp: number;
}

interface PipelineStage {
  stage_id: string;
  status: 'pending' | 'running' | 'completed' | 'failed' | 'skipped';
  duration_ms: number;
  retries: number;
  error_message?: string;
  output_size?: number;
}

interface UserProfile {
  username: string;
  email: string;
  display_name: string;
  role: 'admin' | 'editor' | 'viewer';
  verified: boolean;
  login_count: number;
  last_login?: string;
  bio?: string;
}

interface NetworkPeer {
  peer_id: string;
  address: string;
  port: number;
  connected: boolean;
  latency_ms: number;
  protocol: 'tcp' | 'udp' | 'quic';
  bytes_sent: number;
  bytes_received: number;
}

interface BuildArtifact {
  name: string;
  format: 'binary' | 'docker' | 'npm' | 'wheel';
  version: string;
  size_mb: number;
  signed: boolean;
}

interface AlertRule {
  rule_id: string;
  severity: 'info' | 'warning' | 'critical';
  condition: string;
  threshold: number;
  enabled: boolean;
  cooldown_minutes?: number;
  last_triggered?: string;
}

interface MigrationStep {
  step_number: number;
  description: string;
  reversible: boolean;
  applied: boolean;
  applied_at?: string;
}

interface FeatureFlag {
  flag_name: string;
  enabled: boolean;
  rollout_percent: number;
  environment: 'dev' | 'staging' | 'prod';
  owner?: string;
}

interface ResourceLimit {
  resource: 'cpu' | 'memory' | 'disk' | 'network';
  limit: number;
  current_usage: number;
  unit: string;
  exceeded: boolean;
}

interface WebhookConfig {
  url: string;
  secret: string;
  events: string[];
  active: boolean;
  retry_policy: 'none' | 'linear' | 'exponential';
  max_retries?: number;
}

interface HealthCheck {
  service_name: string;
  status: 'healthy' | 'degraded' | 'unhealthy';
  response_time_ms: number;
  last_check: string;
  consecutive_failures: number;
  dependencies?: string[];
}

interface TaskSchedule {
  task_id: string;
  cron_expression: string;
  timezone: string;
  next_run: string;
  last_run?: string;
  enabled: boolean;
  timeout_seconds: number;
}

interface SearchResult {
  query: string;
  total_hits: number;
  page: number;
  page_size: number;
  took_ms: number;
  timed_out: boolean;
}

interface RateLimitInfo {
  limit: number;
  remaining: number;
  reset_at: string;
  window: 'second' | 'minute' | 'hour' | 'day';
  exceeded: boolean;
}

interface GitCommit {
  sha: string;
  author: string;
  message: string;
  timestamp: string;
  branch: string;
  merge: boolean;
  files_changed: number;
}

interface CertificateInfo {
  domain: string;
  issuer: string;
  valid_from: string;
  valid_to: string;
  fingerprint: string;
  expired: boolean;
  days_remaining: number;
}

interface PluginManifest {
  plugin_id: string;
  version: string;
  author: string;
  enabled: boolean;
  priority: number;
  dependencies?: string[];
  config_schema?: string;
}

interface SessionInfo {
  session_id: string;
  user_agent: string;
  ip_address: string;
  active: boolean;
  created_at: string;
  idle_seconds: number;
}

interface BackupRecord {
  backup_id: string;
  type: 'full' | 'incremental' | 'differential';
  size_mb: number;
  completed: boolean;
  duration_seconds: number;
  verified: boolean;
}

interface NotificationPrefs {
  email_enabled: boolean;
  push_enabled: boolean;
  sms_enabled: boolean;
  digest: 'realtime' | 'hourly' | 'daily' | 'weekly';
  quiet_hours?: string;
}

interface VersionInfo {
  major: number;
  minor: number;
  patch: number;
  prerelease?: string;
  build_number?: number;
  channel: 'stable' | 'beta' | 'nightly';
}

interface DnsRecord {
  hostname: string;
  record_type: 'A' | 'AAAA' | 'CNAME' | 'MX' | 'TXT';
  value: string;
  ttl: number;
  proxied: boolean;
}

